class UserStore:
    """Thread-safe in-memory user store."""

    def __init__(self):
        self._users: dict = {}
        self._lock = threading.Lock()
        self._setup_demo_users()

    def _setup_demo_users(self):
        """Create demo users for testing."""
        demo_users = [
            {
                "user_id": str(uuid.uuid4()),
                "username": "admin",
                "email": "admin@example.com",
                "password_hash": SecurePasswordManager.hash_password("Admin@12345"),
                "roles": ["admin", "user"],
                "created_at": int(time.time()),
            },
            {
                "user_id": str(uuid.uuid4()),
                "username": "testuser",
                "email": "test@example.com",
                "password_hash": SecurePasswordManager.hash_password("Test@12345"),
                "roles": ["user"],
                "created_at": int(time.time()),
            },
            {
                "user_id": str(uuid.uuid4()),
                "username": "readonly",
                "email": "readonly@example.com",
                "password_hash": SecurePasswordManager.hash_password("Read@12345"),
                "roles": ["readonly"],
                "created_at": int(time.time()),
            },
        ]
        for user in demo_users:
            self._users[user["username"]] = user

    def get_by_username(self, username: str) -> Optional[dict]:
        with self._lock:
            return self._users.get(username)

    def get_by_id(self, user_id: str) -> Optional[dict]:
        with self._lock:
            for user in self._users.values():
                if user["user_id"] == user_id:
                    # Return copy without password hash
                    return {k: v for k, v in user.items() if k != "password_hash"}
            return None

    def list_users(self, page: int = 1, page_size: int = 10) -> tuple:
        with self._lock:
            all_users = [
                {k: v for k, v in u.items() if k != "password_hash"}
                for u in self._users.values()
            ]
            total = len(all_users)
            start = (page - 1) * page_size
            end = start + page_size
            return all_users[start:end], total


class ResourceStore:
    """Thread-safe in-memory resource store."""

    def __init__(self):
        self._resources: dict = {}
        self._lock = threading.Lock()
        self._setup_demo_resources()

    def _setup_demo_resources(self):
        """Create demo resources."""
        for i in range(20):
            rid = str(uuid.uuid4())
            self._resources[rid] = {
                "resource_id": rid,
                "data": json.dumps({"name": f"Resource {i+1}", "value": i * 10}),
                "timestamp": int(time.time()),
            }

    def get_by_id(self, resource_id: str) -> Optional[dict]:
        with self._lock:
            return self._resources.get(resource_id)

    def list_resources(self, filter_str: str = "") -> list:
        with self._lock:
            resources = list(self._resources.values())
            if filter_str:
                sanitized = InputValidator.sanitize_string(filter_str, 256)
                resources = [
                    r for r in resources
                    if sanitized.lower() in r["data"].lower()
                ]
            return resources


