class AuthInterceptor(grpc.ServerInterceptor):
    """Server interceptor for authentication, rate limiting, and logging."""

    # Methods that don't require authentication
    UNAUTHENTICATED_METHODS = {
        "/microservices.AuthService/Login",
    }

    def __init__(self, token_manager: SecureTokenManager, rate_limiter: RateLimiter):
        self._token_manager = token_manager
        self._rate_limiter = rate_limiter

    def intercept_service(self, continuation, handler_call_details):
        method = handler_call_details.method
        metadata = dict(handler_call_details.invocation_metadata or [])

        # Rate limiting by peer
        peer_id = metadata.get("x-peer-id", "unknown")
        if not self._rate_limiter.is_allowed(peer_id):
            logger.warning(f"Rate limit exceeded for peer: {peer_id}")
            return grpc.unary_unary_rpc_method_handler(
                lambda req, ctx: ctx.abort(
                    grpc.StatusCode.RESOURCE_EXHAUSTED,
                    "Rate limit exceeded. Please try again later.",
                )
            )

        logger.info(f"Request to method: {method}")

        return continuation(handler_call_details)


