    class AuthServiceServicer(service_pb2_grpc.AuthServiceServicer):
        """Authentication service implementation."""

        def __init__(
            self,
            token_manager: SecureTokenManager,
            user_store: UserStore,
            rate_limiter: RateLimiter,
        ):
            self._token_manager = token_manager
            self._user_store = user_store
            self._rate_limiter = rate_limiter
            self._login_rate_limiter = RateLimiter(
                max_requests=5, window_seconds=60
            )

        def Login(self, request, context):
            """Handle login requests."""
            username = InputValidator.sanitize_string(request.username, 32)
            password = request.password

            # Validate inputs
            valid, msg = InputValidator.validate_username(username)
            if not valid:
                logger.warning(f"Login failed: invalid username format")
                return service_pb2.LoginResponse(
                    success=False, message="Invalid credentials"
                )

            valid, msg = InputValidator.validate_password(password)
            if not valid:
                logger.warning(f"Login failed: invalid password format")
                return service_pb2.LoginResponse(
                    success=False, message="Invalid credentials"
                )

            # Rate limit login attempts per username
            if not self._login_rate_limiter.is_allowed(f"login:{username}"):
                logger.warning(f"Login rate limit exceeded for user: {username}")
                context.set_code(grpc.StatusCode.RESOURCE_EXHAUSTED)
                return service_pb2.LoginResponse(
                    success=False,
                    message="Too many login attempts. Please try again later.",
                )

            # Authenticate
            user = self._user_store.get_by_username(username)
            if not user or not SecurePasswordManager.verify_password(
                password, user["password_hash"]
            ):
                logger.info(f"Login failed for user: {username}")
                # Use constant-time response to prevent timing attacks
                return service_pb2.LoginResponse(
                    success=False, message="Invalid credentials"
                )

            # Generate tokens
            token_pair = self._token_manager.create_token_pair(
                user["user_id"], user["username"], user["roles"]
            )

            logger.info(f"Login successful for user: {username}")
            return service_pb2.LoginResponse(
                success=True,
                token=token_pair["token"],
                refresh_token=token_pair["refresh_token"],
                message="Login successful",
                expires_at=token_pair["expires_at"],
            )

        def ValidateToken(self, request, context):
            """Validate an access token."""
            token = request.token

            valid, msg = InputValidator.validate_token_format(token)
            if not valid:
                return service_pb2.ValidateTokenResponse(valid=False)

            token_data = self._token_manager.validate_token(token)
            if not token_data:
                return service_pb2.ValidateTokenResponse(valid=False)

            return service_pb2.ValidateTokenResponse(
                valid=True,
                user_id=token_data["user_id"],
                username=token_data["username"],
                roles=token_data["roles"],
            )

        def Logout(self, request, context):
            """Handle logout requests."""
            token = request.token

            valid, msg = InputValidator.validate_token_format(token)
            if not valid:
                return service_pb2.LogoutResponse(
                    success=False, message="Invalid token"
                )

            revoked = self._token_manager.revoke_token(token)
            if revoked:
                logger.info("Token revoked successfully")
                return service_pb2.LogoutResponse(
                    success=True, message="Logged out successfully"
                )
            return service_pb2.LogoutResponse(
                success=False, message="Token not found or already revoked"
            )

        def RefreshToken(self, request, context):
            """Refresh an access token."""
            refresh_token = request.refresh_token

            valid, msg = InputValidator.validate_token_format(refresh_token)
            if not valid:
                return service_pb2.RefreshTokenResponse(
                    success=False, message="Invalid refresh token"
                )

            result = self._token_manager.refresh_access_token(refresh_token)
            if not result:
                return service_pb2.RefreshTokenResponse(
                    success=False, message="Invalid or expired refresh token"
                )

            return service_pb2.RefreshTokenResponse(
                success=True,
                token=result["token"],
                refresh_token=result["refresh_token"],
                expires_at=result["expires_at"],
                message="Token refreshed successfully",
            )

