        def _authenticate(self, token: str, context) -> Optional[dict]:
            """Authenticate a request using the token."""
            valid, msg = InputValidator.validate_token_format(token)
            if not valid:
                context.abort(grpc.StatusCode.UNAUTHENTICATED, "Invalid token")
                return None

            token_data = self._token_manager.validate_token(token)
